<?php require_once 'db.php'; require_once 'mailer.php'; $u=require_login('librarian'); verify_csrf(); if($_SERVER['REQUEST_METHOD']==='POST'){ $bid=(int)$_POST['booking_id']; $action=$_POST['action']??''; $reason=trim($_POST['reason']??''); $st=pdo()->prepare('SELECT b.*,usr.email,usr.name FROM bookings b JOIN users usr ON usr.id=b.student_id WHERE b.id=?'); $st->execute([$bid]); $b=$st->fetch(); if($b && in_array($action,['accepted','rejected'],true)){ if($action==='accepted'){ $start=date('Y-m-d'); $expiry=date('Y-m-d',strtotime('+'.$b['duration_days'].' days')); pdo()->prepare("UPDATE bookings SET status='accepted',start_date=?,expiry_date=?,reviewed_by=? WHERE id=? AND NOT EXISTS(SELECT 1 FROM (SELECT id FROM bookings WHERE table_id=? AND status='accepted' AND expiry_date>=CURDATE()) x)")->execute([$start,$expiry,$u['id'],$bid,$b['table_id']]); pdo()->prepare("UPDATE payments SET status='verified' WHERE booking_id=?")->execute([$bid]); [$sub,$body]=email_template('accepted',['name'=>$b['name'],'start'=>$start,'expiry'=>$expiry]); } else { pdo()->prepare("UPDATE bookings SET status='rejected',rejection_reason=?,reviewed_by=? WHERE id=?")->execute([$reason,$u['id'],$bid]); pdo()->prepare("UPDATE payments SET status='rejected' WHERE booking_id=?")->execute([$bid]); [$sub,$body]=email_template('rejected',['name'=>$b['name'],'reason'=>$reason]); } send_library_mail($b['student_id'],$b['email'],$sub,$body); }} $pending=pdo()->query("SELECT b.*,t.table_code,u.name,u.email,p.transaction_id FROM bookings b JOIN users u ON u.id=b.student_id JOIN library_tables t ON t.id=b.table_id LEFT JOIN payments p ON p.booking_id=b.id WHERE b.status='pending' ORDER BY b.created_at")->fetchAll(); $confirmed=pdo()->query("SELECT b.*,t.table_code,u.name FROM bookings b JOIN users u ON u.id=b.student_id JOIN library_tables t ON t.id=b.table_id WHERE b.status='accepted' ORDER BY b.expiry_date DESC")->fetchAll(); app_header('Librarian Dashboard'); ?><h1>Librarian Dashboard</h1><section class="card"><h2>Pending bookings</h2><table><tr><th>Student</th><th>Table</th><th>Amount</th><th>Txn</th><th>Action</th></tr><?php foreach($pending as $b):?><tr><td><?=e($b['name'])?><br><?=e($b['email'])?></td><td><?=e($b['table_code'])?></td><td>₹<?=e($b['amount'])?></td><td><?=e($b['transaction_id'])?></td><td><form method="post" class="inline"><?=csrf_field()?><input type="hidden" name="booking_id" value="<?=e($b['id'])?>"><input name="reason" placeholder="Reject reason"><button name="action" value="accepted" class="btn small">Accept</button><button name="action" value="rejected" class="btn small danger">Reject</button></form></td></tr><?php endforeach;?></table></section><section class="card"><h2>Confirmed bookings</h2><table><tr><th>Student</th><th>Table</th><th>Expiry</th></tr><?php foreach($confirmed as $b):?><tr><td><?=e($b['name'])?></td><td><?=e($b['table_code'])?></td><td><?=e($b['expiry_date'])?></td></tr><?php endforeach;?></table></section><?php app_footer(); ?>
